+// =============================================================================
+// Standard normal CDF & quantile (no external deps)
+// =============================================================================
+
+/// Standard normal CDF using the Abramowitz & Stegun approximation.
+/// Accurate to ~1.5e-7.
+fn standard_normal_cdf(x: f64) -> f64 {
+    if x.is_nan() {
+        return 0.5;
+    }
+    if x > 8.0 {
+        return 1.0;
+    }
+    if x < -8.0 {
+        return 0.0;
+    }
+
+    // Use the polynomial approximation.
+    let sign = if x >= 0.0 { 1.0 } else { -1.0 };
+    let abs_x = x.abs();
+
+    let t = 1.0 / 0.231_641_9f64.mul_add(abs_x, 1.0);
+    let t2 = t * t;
+    let t3 = t2 * t;
+    let t4 = t3 * t;
+    let t5 = t4 * t;
+
+    let poly = 1.330_274_429f64.mul_add(
+        t5,
+        1.821_255_978f64.mul_add(
+            -t4,
+            1.781_477_937f64.mul_add(t3, 0.319_381_530f64.mul_add(t, -(0.356_563_782 * t2))),
+        ),
+    );
+
+    let pdf = (-abs_x * abs_x / 2.0).exp() / (2.0 * std::f64::consts::PI).sqrt();
+    let cdf_positive = 1.0 - pdf * poly;
+
+    0.5 + sign * (cdf_positive - 0.5)
+}
+
+/// Standard normal quantile (inverse CDF) via bisection on our CDF.
+/// Converges to ~1e-8 accuracy in ~50 iterations.
+fn standard_normal_quantile(p: f64) -> f64 {
+    if p <= 0.0 {
+        return f64::NEG_INFINITY;
+    }
+    if p >= 1.0 {
+        return f64::INFINITY;
+    }
+    if (p - 0.5).abs() < 1e-15 {
+        return 0.0;
+    }
+
+    // Bisection search: find z such that CDF(z) = p.
+    let mut lo = -8.0f64;
+    let mut hi = 8.0f64;
+
+    for _ in 0..100 {
+        let mid = f64::midpoint(lo, hi);
+        let cdf_mid = standard_normal_cdf(mid);
+        if cdf_mid < p {
+            lo = mid;
+        } else {
+            hi = mid;
+        }
+        if (hi - lo) < 1e-10 {
+            break;
+        }
+    }
+
+    f64::midpoint(lo, hi)
+}
